Do scraping ao dataset limpo

library(rvest)
library(tidyverse)
library(lubridate)

# 1. Coletar
paginas &lt;- paste0(
  "https://agenciabrasil.ebc.com.br/internacional?page=",
  0:4
)

df_bruto &lt;- purrr::map_dfr(paginas, function(url) {
  Sys.sleep(1.5)
  pagina &lt;- tryCatch(read_html(url), error = function(e) NULL)
  if (is.null(pagina)) return(tibble())
  tibble(
    titulo = pagina |&gt; html_elements("h2") |&gt; html_text2(),
    link   = pagina |&gt; html_elements("h2 a") |&gt; html_attr("href"),
    coletado = Sys.time()
  )
})

# 2. Limpar
df_limpo &lt;- df_bruto |&gt;
  mutate(titulo = str_squish(titulo)) |&gt;
  filter(nchar(titulo) &gt; 20) |&gt;
  distinct(link, .keep_all = TRUE)

# 3. Salvar
write_csv(df_limpo, "data/processed/noticias_internacionais.csv")

