API do GDELT

library(httr2)
library(jsonlite)

buscar_gdelt &lt;- function(query, max_records = 25) {

  url &lt;- paste0(
    "https://api.gdeltproject.org/api/v2/doc/doc",
    "?query=", URLencode(query),
    "&mode=artlist",
    "&maxrecords=", max_records,
    "&format=json"
  )

  resp &lt;- tryCatch(
    request(url) |&gt;
      req_user_agent("Curso RI / pesquisa academica") |&gt;
      req_timeout(20) |&gt;
      req_perform(),
    error = function(e) NULL
  )

  if (is.null(resp)) return(tibble())

  dados &lt;- resp |&gt; resp_body_string() |&gt; fromJSON()

  if (is.null(dados$articles)) return(tibble())

  as_tibble(dados$articles)
}

