Padrão de coleta

coletar_com_scroll &lt;- function(url, n_scrolls = 10) {

  remDr$navigate(url)
  Sys.sleep(3)

  todos_titulos &lt;- character(0)

  for (i in seq_len(n_scrolls)) {

    html_atual &lt;- remDr$getPageSource()[[1]]
    pagina &lt;- read_html(html_atual)

    titulos &lt;- pagina |&gt;
      html_elements(".titulo") |&gt;
      html_text2()

    novos &lt;- setdiff(titulos, todos_titulos)
    todos_titulos &lt;- unique(c(todos_titulos, titulos))

    cat(sprintf("Scroll %d: +%d títulos (%d total)\n",
                i, length(novos), length(todos_titulos)))

    # Scrollar
    remDr$executeScript(
      "window.scrollTo(0, document.body.scrollHeight);"
    )
    Sys.sleep(2)

    if (length(novos) == 0) {
      cat("Sem novos elementos — encerrando.\n")
      break
    }
  }

  todos_titulos
}

Espera explícita

aguardar_elemento &lt;- function(remDr, seletor, timeout = 10) {

  inicio &lt;- Sys.time()

  repeat {
    elemento &lt;- tryCatch(
      remDr$findElement("css selector", seletor),
      error = function(e) NULL
    )

    if (!is.null(elemento)) return(elemento)

    if (as.numeric(Sys.time() - inicio) &gt; timeout) {
      stop(sprintf("Timeout: elemento '%s' não apareceu.", seletor))
    }

    Sys.sleep(0.5)
  }
}

