Câmara dos Deputados — votações

coletar_votacoes_camara &lt;- function(legislatura = 57) {

  driver &lt;- rsDriver(browser = "chrome", verbose = FALSE, port = 4445L)
  remDr  &lt;- driver$client
  on.exit({ remDr$close(); driver$server$stop() })

  url &lt;- paste0(
    "https://www.camara.leg.br/votacoes#",
    "legislatura=", legislatura
  )

  remDr$navigate(url)
  Sys.sleep(4)

  resultados &lt;- list()

  for (p in 1:5) {

    html &lt;- remDr$getPageSource()[[1]]
    pagina &lt;- read_html(html)

    votos &lt;- pagina |&gt;
      html_elements(".pauta-votacao") |&gt;
      html_text2()

    if (length(votos) &gt; 0) {
      resultados[[p]] &lt;- tibble(votacao = votos, pagina = p)
    }

    # Próxima página
    btn_prox &lt;- tryCatch(
      remDr$findElement("css selector", ".paginacao-proxima"),
      error = function(e) NULL
    )

    if (is.null(btn_prox)) break

    btn_prox$clickElement()
    Sys.sleep(2)
  }

  bind_rows(resultados)
}

